\displaystyle{\begin{aligned}
   {\frac{\frac{2y}{y^{2}-4}-3}{\frac{5}{y+2}-\frac{1}{y-2}}}
      \amp = {\frac{\frac{2y}{\left(y+2\right)\mathopen{}\left(y-2\right)}-3}{\frac{5}{y+2}-\frac{1}{y-2}}} \\
      \amp = {\frac{\frac{2y}{\left(y+2\right)\mathopen{}\left(y-2\right)}-3}{\frac{5}{y+2}-\frac{1}{y-2}}} \cdot \frac{{\left(y+2\right)\mathopen{}\left(y-2\right)}}{{\left(y+2\right)\mathopen{}\left(y-2\right)}} \\
      \amp = {\frac{\frac{2y}{\left(y+2\right)\mathopen{}\left(y-2\right)}\mathopen{}\left(y+2\right)\mathopen{}\left(y-2\right)-3\mathopen{}\left(y+2\right)\mathopen{}\left(y-2\right)}{\frac{5}{y+2}\mathopen{}\left(y+2\right)\mathopen{}\left(y-2\right)-\frac{1}{y-2}\mathopen{}\left(y+2\right)\mathopen{}\left(y-2\right)}} \\
      \amp = {\frac{2y-3\mathopen{}\left(y^{2}-4\right)}{5\mathopen{}\left(y-2\right)-\left(y+2\right)}}, y \ne 2 \text{ and } y \ne -2 \\
      \amp = {\frac{2y-3y^{2}+12}{5y-10-y-2}}, y \ne 2 \text{ and } y \ne -2 \\
      \amp = {\frac{-3y^{2}+2y+12}{4\mathopen{}\left(y-3\right)}, y\ne -2\hbox{ and }y\ne 2}
